import { format, parseISO } from 'date-fns';
import { arSA } from 'date-fns/locale';
import { toZonedTime } from 'date-fns-tz';

const timeZone = 'Asia/Riyadh';

/**
 * تنسيق التاريخ والوقت (YYYY-MM-DD HH:mm:ss) بتوقيت السعودية
 * @param {string|Date} date - التاريخ المدخل (يفضل أن يكون بصيغة ISO)
 * @returns {string} التاريخ المنسق
 */
export const formatDateTime = (date) => {
  if (!date) return '';
  try {
    const dateObj = typeof date === 'string' ? parseISO(date) : date;
    const zonedDate = toZonedTime(dateObj, timeZone);
    return format(zonedDate, 'yyyy-MM-dd HH:mm:ss', { locale: arSA });
  } catch (e) {
    console.error('Error formatting date:', e);
    return String(date);
  }
};

/**
 * تنسيق التاريخ فقط (YYYY-MM-DD)
 * @param {string|Date} date
 * @returns {string}
 */
export const formatDate = (date) => {
  if (!date) return '';
  try {
    const dateObj = typeof date === 'string' ? parseISO(date) : date;
    const zonedDate = toZonedTime(dateObj, timeZone);
    return format(zonedDate, 'yyyy-MM-dd', { locale: arSA });
  } catch (e) {
    return String(date);
  }
};

/**
 * تنسيق الوقت فقط (HH:mm:ss)
 * @param {string|Date} date
 * @returns {string}
 */
export const formatTime = (date) => {
  if (!date) return '';
  try {
    const dateObj = typeof date === 'string' ? parseISO(date) : date;
    const zonedDate = toZonedTime(dateObj, timeZone);
    return format(zonedDate, 'HH:mm:ss', { locale: arSA });
  } catch (e) {
    return String(date);
  }
};

/**
 * الحصول على التاريخ والوقت الحالي بتوقيت السعودية
 * @returns {string} التاريخ والوقت الحالي
 */
export const now = () => {
  return format(new Date(), 'yyyy-MM-dd HH:mm:ss', { locale: arSA });
};

/**
 * تحويل تاريخ من قاعدة البيانات (UTC) إلى كائن Date محلي
 * @param {string} utcDate
 * @returns {Date}
 */
export const utcToLocalDate = (utcDate) => {
  if (!utcDate) return null;
  const date = parseISO(utcDate);
  return toZonedTime(date, timeZone);
};
